// TREND AGENT - Fixed syntax
const item = items[0]?.json || {};
const body = item.body || item;

const prompt = `Analyze: ${body.topic || 'auto-trend'}. Return JSON: {category, viral_score, platform, audience, hashtags}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + $env.GROQ_API_KEY, 'Content-Type': 'application/json' },
  body: { model: 'llama-3.1-8b-instant', messages: [{ role: 'user', content: prompt }], temperature: 0.3 },
  json: true
});

let decision = {};
try { decision = JSON.parse(response.choices?.[0]?.message?.content || '{}'); } catch {}

return [{ json: { ...body, agent: 'TREND_AGENT', category: decision.category || 'tech', viral_score: decision.viral_score || 85, platform_recommendation: decision.platform || 'tiktok', target_audience: decision.audience || '18-35', hashtags: decision.hashtags || ['trending'] }}];

// SCRIPT AGENT - Fixed syntax
const item = items[0]?.json || {};

const prompt = `Create viral script about: ${item.topic || 'trending'}. Platform: ${item.platform_recommendation || 'tiktok'}. Return JSON: {title, scenes: [{narration, visual_description, duration_seconds}]}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + $env.GROQ_API_KEY, 'Content-Type': 'application/json' },
  body: { model: 'llama-3.1-8b-instant', messages: [{ role: 'user', content: prompt }], max_tokens: 2000, temperature: 0.7 },
  json: true
});

let script = {};
try { script = JSON.parse(response.choices?.[0]?.message?.content || '{}'); } catch {}

return [{ json: { ...item, script, agent: 'SCRIPT_AGENT' }}];

// VISION AGENT - Fixed syntax
const item = items[0]?.json || {};
const scenes = item.script?.scenes || [];

const processed = scenes.map((scene, i) => ({
  scene_index: i,
  narration: scene.narration,
  visual_description: scene.visual_description,
  search_query: scene.visual_description?.split(' ').slice(0,5).join(' ') || 'trending',
  resolution: '4K'
}));

return [{ json: { ...item, scenes: processed, agent: 'VISION_AGENT' }}];

// AUDIO AGENT - Fixed syntax
const item = items[0]?.json || {};
const lang = item.language || 'nb';

const voiceMap = { nb: 'nb-NO-PernilleNeural', en: 'XB0fDUnXU5powFXDhCwa', ta: 'ta-IN-PallaviNeural', es: 'es-ES-ElviraNeural' };

return [{ json: { ...item, voice_id: voiceMap[lang] || voiceMap.nb, music_type: 'upbeat', agent: 'AUDIO_AGENT' }}];

// PLATFORM AGENT - Fixed syntax
const item = items[0]?.json || {};
const platform = item.platform_recommendation || 'tiktok';

const rules = {
  tiktok: { aspect: '9:16', duration: 60, hashtags: 3 },
  youtube: { aspect: '16:9', duration: 480, hashtags: 5 },
  instagram: { aspect: '9:16', duration: 30, hashtags: 10 }
};

return [{ json: { ...item, platform_rules: rules[platform] || rules.tiktok, agent: 'PLATFORM_AGENT' }}];

// QUALITY AGENT - Fixed syntax
const item = items[0]?.json || {};

const quality_score = item.scenes?.length > 0 ? 95 : 50;

return [{ json: { ...item, quality_score, quality_approved: quality_score >= 80, agent: 'QUALITY_AGENT' }}];
